import React from "react";
import {
  BookOpenIcon,
  ClipboardDocumentListIcon,
  ChartBarIcon,
  AcademicCapIcon,
  StarIcon,
  UserGroupIcon,
  Cog6ToothIcon,
  DocumentChartBarIcon,
} from "@heroicons/react/24/outline";
import { Link } from "react-router-dom";

export default function Dashboard() {
  const role = localStorage.getItem("role");

  if (!role) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <h1 className="text-xl font-semibold text-gray-700">
          Please login first
        </h1>
      </div>
    );
  }

  const isStudent = role === "Student";
  const isAdmin = role === "Admin";
  const isPanel = role === "Academic Panel";

  return (
    <div className="relative min-h-screen bg-gradient-to-br from-indigo-50 via-white to-blue-50 px-6 py-10 overflow-hidden">

      {/* background glow */}
      <div className="absolute top-[-100px] left-[-100px] w-[300px] h-[300px] bg-indigo-300 blur-[120px] opacity-40 rounded-full" />
      <div className="absolute bottom-[-120px] right-[-120px] w-[350px] h-[350px] bg-blue-300 blur-[130px] opacity-30 rounded-full" />

      <div className="max-w-6xl mx-auto relative z-10">

        {/* HEADER */}
        <div className="text-center mb-10">
          <div className="inline-flex items-center gap-2 px-4 py-1 bg-white shadow-sm rounded-full text-sm text-gray-600">
            Logged in as
            <span className="font-semibold text-indigo-600">{role}</span>
          </div>

          <h1 className="text-4xl font-bold text-gray-800 mt-4">
            Welcome to your Dashboard
          </h1>

          <p className="text-gray-500 mt-2">
            Everything you need in one place
          </p>
        </div>

        {/* STUDENT */}
        {isStudent && (
          <Section title="Student Tools">
            <DashboardCard
              title="Resources"
              icon={<BookOpenIcon />}
              color="indigo"
              to="/resources"
            />
            <DashboardCard
              title="My Tasks"
              icon={<ClipboardDocumentListIcon />}
              color="green"
              to="/tasks"
            />
            <DashboardCard
              title="Reviews"
              icon={<StarIcon />}
              color="purple"
              to="/reviews"
            />
            <DashboardCard
              title="Quizzes"
              icon={<AcademicCapIcon />}
              color="pink"
              to="/quiz-bank"
            />
            <DashboardCard
              title="Study Sessions"
              icon={<ChartBarIcon />}
              color="yellow"
              to="/sessions"
            />
          </Section>
        )}

        {/* ADMIN */}
        {isAdmin && (
          <Section title="Admin Control Panel">
            <DashboardCard title="Manage Users" icon={<UserGroupIcon />} color="red" to="/admin/users" />
            <DashboardCard title="System Settings" icon={<Cog6ToothIcon />} color="gray" />
            <DashboardCard title="Reports" icon={<DocumentChartBarIcon />} color="blue" />
            <DashboardCard title="Resources" icon={<BookOpenIcon />} color="indigo" />
          </Section>
        )}

        {/* ACADEMIC PANEL */}
        {isPanel && (
          <Section title="Academic Panel Tools">
            <DashboardCard title="Review Students" icon={<UserGroupIcon />} color="blue" />
            <DashboardCard title="Manage Courses" icon={<BookOpenIcon />} color="indigo" />
            <DashboardCard title="Analytics" icon={<ChartBarIcon />} color="purple" />
            <DashboardCard title="All Resources" icon={<BookOpenIcon />} color="green" />
            <DashboardCard title="My Resources" icon={<BookOpenIcon />} color="yellow" />
          </Section>
        )}
      </div>
    </div>
  );
}

/* SECTION WRAPPER */
function Section({ title, children }) {
  return (
    <div className="mb-12">
      <h2 className="text-xl font-semibold text-gray-700 mb-6">
        {title}
      </h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {children}
      </div>
    </div>
  );
}

/* CARD */
function DashboardCard({ title, icon, color, to }) {
  const colorMap = {
    indigo: "from-indigo-500 to-indigo-600",
    green: "from-green-500 to-green-600",
    purple: "from-purple-500 to-purple-600",
    pink: "from-pink-500 to-pink-600",
    yellow: "from-yellow-500 to-yellow-600",
    red: "from-red-500 to-red-600",
    gray: "from-gray-500 to-gray-600",
    blue: "from-blue-500 to-blue-600",
  };

  const content = (
    <div className="group bg-white/80 backdrop-blur-lg border border-gray-100 p-6 rounded-2xl shadow-sm hover:shadow-xl transition-all duration-300 cursor-pointer hover:-translate-y-1">

      <div className={`w-12 h-12 rounded-xl bg-gradient-to-r ${colorMap[color]} flex items-center justify-center text-white`}>
        {React.cloneElement(icon, { className: "w-6 h-6" })}
      </div>

      <h3 className="mt-4 text-lg font-semibold text-gray-800 group-hover:text-gray-900">
        {title}
      </h3>

      <p className="text-sm text-gray-500 mt-1">
        Open {title.toLowerCase()}
      </p>
    </div>
  );

  return to ? <Link to={to}>{content}</Link> : content;
}
